var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐야, 호들갑 떨 줄 알았던 녀석들이 되게 조용하네?","JPN":"何よ、騒がしくなると思ったのに静かすぎるんじゃない？","ENG":"Huh? I expected a big reaction, but everyone's awfully quiet.","TWN":"怎麼回事，我以為那些傢伙會大驚小怪，結果卻這麼安靜？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"조심 좀 해, 아가씨. 그동안 단원들을 얼마나 갈궜으면 저렇게 눈치를 봐?","JPN":"気をつけなさいよ、お嬢さん。普段どんだけこき使ったらあんな不安そうな目で見つめられるのかしら。","ENG":"Watch it, missy. Just how hard did you ride the others for them to be that jumpy around you?","TWN":"小心點。你之前對團員們有多嚴厲，他們才會這麼看眼色？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그건 아니라고 생각합니다.","JPN":"それは違うと思います。","ENG":"I don't think that's it.","TWN":"我認為不是這樣。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……아마도.","JPN":"……たぶん。","ENG":"...Probably.","TWN":"……也許吧。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"야, 한솔아. 지금 내가 본 게 맞냐?","JPN":"ちょっと、イチロウ。今、私の目がおかしいんじゃないよね？","ENG":"Hansol, did I really just see what I think I saw?","TWN":"嘿，楊瀚。我剛才看到的是真的嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"적진 한가운데로 함선이 떨어지더니… 거기서 단장이 뛰쳐나왔는데.","JPN":"敵陣の真ん中に艦船が落ちてきて……そこから団長が飛び出たんだけど。","ENG":"A ship crash-landed right in the middle of enemy territory... and Captain leapt out of it.","TWN":"戰艦掉進敵陣中央……然後團長從裡面衝了出來。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"혹시, 저기 있는 단장도 도플갱어 침식체인 건가?","JPN":"もしかして、あそこにいる団長もドッペルゲンガー侵食体なのかな？","ENG":"That's not another Doppelganger-type C.O., is it?","TWN":"難道，那邊的團長也是二重身侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"특수한 아티팩트의 힘이 없는 한 무리라고 생각합니다.","JPN":"特殊なアーティファクトの力がないかぎり、無理だと思いますよ。","ENG":"Without a special Artifact, that would be impossible.","TWN":"我認為這是一群沒有特殊神器力量的人。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 진짜야?","JPN":"じゃあ、本物？","ENG":"So it's really her?","TWN":"那是真的嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"진짜… 인 것 같네요.","JPN":"本物……みたいです。","ENG":"Seems... like it.","TWN":"真的……好像是這樣。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"크으으으으으––––––!!","JPN":"くううううーーーーーー！！","ENG":"Kghh––––––!!","TWN":"咳呃呃呃呃呃––––––！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"늦었잖아, 단장! 지금까지 어디서 뭘 하고 있었던 거야?","JPN":"遅いよ、団長！　今までどこで何をやってたの？","ENG":"You're late, Captain! Where the hell have you been all this time?!","TWN":"太晚了，團長！你到現在都在幹什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그 로브는 뭐야? 스타일 체인지? 아니면, 한솔이 죽도처럼 컨셉 잡은 건가?","JPN":"そのローブは何？　イメチェン？　それとも、イチロウの竹刀みたいな設定？","ENG":"And what's with the robe? Trying out a new style? or are you pulling a Hansol and going for a whole phase like his bamboo sword thing?","TWN":"那件披風是什麼？風格改變？還是像楊瀚一樣是某種人設？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"컨셉이 아니에요!","JPN":"設定じゃないです！","ENG":"It's not a phase!","TWN":"才不是人設！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그렇지만 기다리고 있었습니다, 단장님!!","JPN":"でも、待ってましたよ、団長！！","ENG":"Still, welcome back, Captain!","TWN":"不過，我一直在等你，團長！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그래. 다들 지금까지 잘 버텨줬다.","JPN":"ああ。みんな、今までよく頑張った。","ENG":"Yeah. You've all held out well.","TWN":"是啊，大家到現在都堅持得很好。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"자세한 이야기를 하기에는… 조금 길군. 그건 일이 정리된 이후로 하지.","JPN":"詳しく話すには……少し長い。それはこの戦いが終わってからにしよう。","ENG":"It's a long story... I'll explain once everything's settled.","TWN":"詳細說起來……有點長。等事情處理完再說吧。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"미안하다, 피오네 경. 내가 부족한 탓에 그대에게 큰 짐을 안겼군.","JPN":"すまない、フィオネ卿。私が足りないせいで君に重荷を押しつけることになった。","ENG":"I'm sorry, Dame Fione. My absence placed too much burden on you.","TWN":"抱歉，菲奧尼卿。因為我的無能，給你帶來了沉重的負擔。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"용서를 바라진 않겠어. 다만…….","JPN":"許してほしいとは言わない。ただ……","ENG":"I won't ask for forgiveness, but...","TWN":"我不求你能原諒我，只是……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"답지 않게 유약한 모습을 보이시는군요.","JPN":"弱音を吐くなんて、あなたらしくないですね。","ENG":"That's not like you, Captain.","TWN":"真不像你，居然露出了軟弱的一面。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"평소처럼 <color=#ffd34c>부단장</color>이라고 부르셔도 됩니다, <color=#ffd34c>단장님.</color>","JPN":"いつものように<color=#ffd34c>副団長</color>と呼んでください、<color=#ffd34c>団長</color>。","ENG":"Feel free to call me <color=#ffd34c>Deputy</color>, as usual, <color=#ffd34c>Captain</color>.","TWN":"像平時一樣叫我<color=#ffd34c>副團長</color>就可以了，<color=#ffd34c>團長。</color>"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……그래. 내가 그대에게 괜한 걱정을 끼친 모양이야.","JPN":"……ああ。君に余計な心配をさせてしまったようだ。","ENG":"...Right. I guess I made you worry more than I realized.","TWN":"……是啊，我好像讓你白白擔心了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"명색이 단장이라면, 단원들 앞에서는 모범을 보여야겠지.","JPN":"団長たる者、団員の前ではお手本にならないとな。","ENG":"A captain should always lead by example.","TWN":"既然是團長，在團員面前就要樹立榜樣。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 단장님이 여긴 어떻게…….","JPN":"それにしても、団長はどうやってここに……？","ENG":"But how did you end up here, Captain...?","TWN":"但是團長怎麼會在這……！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};